#include <stdio.h>

#define MOD 1000000007

long long power(long long a, long long p) {
    long long res = 1;
    while (p > 0) {
        if (p % 2 == 1) {
            res = (res * a) % MOD;
        }
        a = (a * a) % MOD;
        p /= 2;
    }
    return res;
}

int main() {
    long long n, m;
    scanf("%lld %lld", &n, &m);
    n += 1;
    long long res = (power(n * 2, m - 1) * (n - m) * 2) % MOD;
    printf("%lld\n", res);
    return 0;
}
